import React, { useRef, useState, useEffect } from 'react';

const ImageCapture = ({ onCapture }) => {
    const videoRef = useRef(null);
    const photoRef = useRef(null);
    const [hasStream, setHasStream] = useState(false);
    const [photo, setPhoto] = useState(null);

    const getVideo = () => {
        navigator.mediaDevices.getUserMedia({
            video: { width: 400, height: 300 }
        })
        .then(stream => {
            let video = videoRef.current;
            if (video) {
                video.srcObject = stream;
                video.play();
                setHasStream(true);
            }
        })
        .catch(err => {
            console.error("Error accessing camera:", err);
            setHasStream(false);
        });
    };

    const takePhoto = () => {
        console.log("takePhoto function called");
        let width = 400;
        let height = 300;

        let video = videoRef.current;
        let photo = photoRef.current;

        if (photo && video) {
            let ctx = photo.getContext('2d');
            photo.width = width;
            photo.height = height;

            ctx.drawImage(video, 0, 0, width, height);
            const imageData = photo.toDataURL('image/png');
            console.log("Image data captured:", imageData.substring(0, 100) + "..."); // Log first 100 chars
            setPhoto(imageData);
            onCapture(imageData); // Pass the captured image data to the parent component
        } else {
            console.log("Photo ref or video ref not available for takePhoto");
        }
    };

    const handleFileSelect = (event) => {
        const file = event.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (e) => {
                const imageData = e.target.result;
                console.log("File data selected:", imageData.substring(0, 100) + "...");
                setPhoto(imageData);
                onCapture(imageData);
            };
            reader.readAsDataURL(file);
        }
    };

    const clearPhoto = () => {
        let photo = photoRef.current;
        if (photo) {
            let ctx = photo.getContext('2d');
            ctx.clearRect(0, 0, photo.width, photo.height);
            setPhoto(null);
        }
    };

    useEffect(() => {
        getVideo();
        return () => {
            // Cleanup: stop video stream when component unmounts
            if (videoRef.current && videoRef.current.srcObject) {
                videoRef.current.srcObject.getTracks().forEach(track => track.stop());
            }
        };
    }, []);

    return (
        <div className="image-capture-container">
            <h3>Capture Photo pour Date de Péremption</h3>
            {!hasStream && (
                <p className="text-sm text-red-400 mb-2">Accès à la caméra refusé ou non disponible. Veuillez autoriser l'accès à la caméra ou télécharger un fichier.</p>
            )}
            {hasStream && (
                <>
                    <video ref={videoRef} className="camera-feed"></video>
                    <button onClick={takePhoto}>Prendre une Photo</button>
                </>
            )}

            <label htmlFor="expiryFile" className="block text-gray-400 mb-1 mt-4">Ou Télécharger une Photo de Date de Péremption</label>
            <input type="file" id="expiryFile" accept="image/*" onChange={handleFileSelect} className="mt-2" />

            <canvas ref={photoRef} style={{ display: 'none' }}></canvas>
            {photo && (
                <div className="photo-preview">
                    <h4>Photo Capturée:</h4>
                    <img src={photo} alt="Capturée" />
                    <button onClick={clearPhoto}>Reprendre Photo</button>
                </div>
            )}
        </div>
    );
};

export default ImageCapture;

