import { getFunctions, httpsCallable } from 'firebase/functions';

const TestFunctionsCall = () => {
  const [message, setMessage] = useState('Initializing...');
  const [functionUrl, setFunctionUrl] = useState('Not available yet');
  const [callResult, setCallResult] = useState('');

  // Initialize functions instance outside of useEffect if possible, but
  // ensure app is ready. For testing, we'll do it here.
  const functionsInstance = getFunctions(app, { region: 'us-central1' });
  const callableFunction = httpsCallable(functionsInstance, 'extractExpiryDateFromImage');

  useEffect(() => {
    // Log the function instance and its derived URL on mount
    console.log("TestFunctionsCall: Functions instance (on mount):", functionsInstance);
    console.log("TestFunctionsCall: Callable function URL (on mount):", callableFunction.url);
    if (callableFunction.url) {
      setFunctionUrl(callableFunction.url);
      setMessage('Ready to call function. URL is available.');
    } else {
      setMessage('Error: Callable function URL is undefined on mount.');
    }
  }, []);

  const handleCallFunction = async () => {
    setCallResult('Calling function...');
    console.log("TestFunctionsCall: Callable function URL (on button click):", callableFunction.url);

    if (!callableFunction.url) {
        setCallResult('Error: Cannot call function, URL is undefined.');
        return;
    }

    try {
      // Send a dummy image data for testing
      const dummyImageData = "data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=";
      const base64Image = dummyImageData.split(',')[1];

      const result = await callableFunction({ image: base64Image });
      setCallResult(`Function responded: ${JSON.stringify(result.data)}`);
    } catch (error) {
      console.error("TestFunctionsCall: Error calling function:", error);
      setCallResult(`Error: ${error.message}`);
    }
  };

  return (
    <div style={{ padding: '20px', border: '1px solid gray', margin: '20px', backgroundColor: '#333', color: 'white' }}>
      <h3>Test Firebase Callable Function</h3>
      <p>Status: {message}</p>
      <p>Resolved Function URL: {functionUrl}</p>
      <button onClick={handleCallFunction} style={{ padding: '10px', marginTop: '10px' }}>
        Call extractExpiryDateFromImage
      </button>
      <p style={{ marginTop: '10px' }}>Result: {callResult}</p>
      <p style={{ color: 'red', marginTop: '10px' }}>
        Check your browser console (F12) for more detailed logs from this component.
      </p>
    </div>
  );
};

export default TestFunctionsCall;

