import React, { useState, useEffect } from 'react';
import app from '../firebase/config'; // Firebase app instance
import { getFunctions, httpsCallable } from 'firebase/functions'; // Keep for context, but not used in direct fetch

const TestFunctionsCall = () => {
  const [message, setMessage] = useState('Initializing...');
  const [functionUrl, setFunctionUrl] = useState('Not available yet');
  const [callResult, setCallResult] = useState('');

  // Expected URL for the callable function
  // Format: https://{REGION}-{PROJECT_ID}.cloudfunctions.net/{functionName}
  const expectedFunctionUrl = `https://us-central1-dashboard-mictlan-dev.cloudfunctions.net/extractExpiryDateFromImage`;

  useEffect(() => {
    // Log the expected URL on mount
    console.log("TestFunctionsCall: Expected Function URL:", expectedFunctionUrl);
    setFunctionUrl(expectedFunctionUrl);
    setMessage('Ready to call function directly via fetch.');
  }, []);

  const handleCallFunction = async () => {
    setCallResult('Calling function directly via fetch...');
    console.log("TestFunctionsCall: Calling URL:", expectedFunctionUrl);

    try {
      // Data format for callable functions is specific: { data: your_payload }
      const requestBody = {
        data: {
          image: "iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=" // Dummy base64 image
        }
      };

      const response = await fetch(expectedFunctionUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          // Firebase callable functions also expect a specific header 'X-Firebase-AppCheck' if App Check is enabled
          // or an Authorization header for authenticated users if configured
          // For simplicity in testing, we omit these, but they might be needed for a production setup.
        },
        body: JSON.stringify(requestBody),
      });

      if (!response.ok) {
        // Callable functions return 200 even on error, but the body contains error details
        // For direct fetch, we check response.ok and then parse the body
        const errorText = await response.text();
        throw new Error(`HTTP error! status: ${response.status}, body: ${errorText}`);
      }

      const responseData = await response.json();
      console.log("Raw function response:", responseData);

      // Callable functions wrap their response in a 'result' field
      if (responseData.data && responseData.data.expiryDate) {
        setCallResult(`Function responded (direct fetch): Date: ${responseData.data.expiryDate}, Message: ${responseData.data.message}`);
      } else if (responseData.data) {
        setCallResult(`Function responded (direct fetch): ${responseData.data.message}`);
      } else {
        // If the function returns an error, it will be in the 'error' field
        setCallResult(`Function responded with error (direct fetch): ${JSON.stringify(responseData.error || responseData)}`);
      }

    } catch (error) {
      console.error("TestFunctionsCall: Error calling function directly:", error);
      setCallResult(`Error during direct fetch: ${error.message}`);
    }
  };

  return (
    <div style={{ padding: '20px', border: '1px solid gray', margin: '20px', backgroundColor: '#333', color: 'white' }}>
      <h3>Test Firebase Callable Function (Direct Fetch)</h3>
      <p>Status: {message}</p>
      <p>Resolved Function URL: {functionUrl}</p>
      <button onClick={handleCallFunction} style={{ padding: '10px', marginTop: '10px' }}>
        Call extractExpiryDateFromImage (Direct Fetch)
      </button>
      <p style={{ marginTop: '10px' }}>Result: {callResult}</p>
      <p style={{ color: 'red', marginTop: '10px' }}>
        Check your browser console (F12) for more detailed logs from this component.
      </p>
    </div>
  );
};

export default TestFunctionsCall;

