        setExpiryDate(responseData.data.expiryDate);
        setOcrFeedback('Date détectée avec succès !');
      } else if (responseData.data) {
        setOcrFeedback(responseData.data.message);
      } else {
        setOcrFeedback(`Erreur inattendue: ${JSON.stringify(responseData)}`);
      }

